import React from "react";
import "./PathologyPage.css";

const PathologyPage = () => {
  const popularHealthCheckups = [
    { title: "STD Checkups", img: "/images/std.png" },
    { title: "Fever Checkups", img: "/images/fever.png" },
    { title: "PCOD Checkups", img: "/images/pcod.png" },
    { title: "Senior Citizen", img: "/images/senior.png" },
  ];

  const popularHealthTests = [
    { title: "Kidney Function Test", img: "/images/kidney.png" },
    { title: "Vitamin D, 25-Hydroxy", img: "/images/vitamin.png" },
    { title: "HbA1c", img: "/images/hba1c.png" },
    { title: "Lipid Profile", img: "/images/lipid.png" },
  ];

  const fullBodyCheckups = [
    {
      title: "Full Body Checkup - Essential",
      price: "₹1599",
      discount: "70% Off",
    },
    {
      title: "Full Body Checkup - Advanced",
      price: "₹2699",
      discount: "68% Off",
    },
    {
      title: "Ultra Full Body Checkup - Male",
      price: "₹11999",
      discount: "66% Off",
    },
  ];

  return (
    <div className="health-container">
      <h2 className="section-title">Popular Health Checkups</h2>
      <div className="card-grid">
        {popularHealthCheckups.map((item, index) => (
          <div className="health-card" key={index}>
            <img src={item.img} alt={item.title} />
            <p>{item.title}</p>
          </div>
        ))}
      </div>

      <h2 className="section-title">Popular Health Tests</h2>
      <div className="card-grid">
        {popularHealthTests.map((item, index) => (
          <div className="health-card" key={index}>
            <img src={item.img} alt={item.title} />
            <p>{item.title}</p>
          </div>
        ))}
      </div>

      <h2 className="section-title">Full Body Checkups</h2>
      <div className="card-grid">
        {fullBodyCheckups.map((item, index) => (
          <div className="checkup-card" key={index}>
            <h3>{item.title}</h3>
            <h4>{item.price}</h4>
            <span className="discount">{item.discount}</span>
            <div className="btn-group">
              <button className="view-btn">View Details</button>
              <button className="cart-btn">Add to Cart</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PathologyPage;
